    bottom: 0;
    padding: 12px 0 env(safe-area-inset-bottom, 16px);
    background: linear-gradient(to top, #fff 70%, transparent);
    margin-top: auto;
}

.screen-bottom {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
    padding-bottom: env(safe-area-inset-bottom, 16px);
    margin-top: auto;
    padding-top: 8px;
}

/* ===================================================================
   SUCCESS SCREEN
   =================================================================== */

.success-icon-wrap {
    animation: successPop 500ms cubic-bezier(0.34, 1.56, 0.64, 1);
}
@keyframes successPop {
    from { transform: scale(0.3); opacity: 0; }
    to   { transform: scale(1);   opacity: 1; }
}
.success-icon {
    width: 112px;
    height: 112px;
    border-radius: 50%;
    background: linear-gradient(135deg, #4ade80, #22c55e);
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 16px 40px rgba(34, 197, 94, 0.35);
    color: #fff;
}
.success-title {
    font-size: 28px;
    font-weight: 800;
    color: var(--text-dark);
    line-height: 1.3;
}
.success-sub {
    font-size: 15px;
    color: var(--text-muted);
    line-height: 1.6;
}
.success-countdown {
    width: 52px;
    height: 52px;
    border-radius: 50%;
    background: var(--blue-light);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 22px;
    font-weight: 800;
    color: var(--blue);
}

/* ===================================================================
   TOAST
   =================================================================== */

.toast {
    position: fixed;
    bottom: calc(24px + env(safe-area-inset-bottom, 0px));
    left: 50%;
    transform: translateX(-50%) translateY(100px);
    background: #1a1a2e;
    color: #fff;
    font-size: 14px;
    font-weight: 600;
    padding: 12px 24px;
    border-radius: 24px;
    white-space: nowrap;
    z-index: 9999;
    opacity: 0;
    transition: transform 250ms ease, opacity 250ms ease;
    max-width: calc(100vw - 48px);
    text-align: center;
}
.toast.show {
    transform: translateX(-50%) translateY(0);
    opacity: 1;
}
.toast.toast--error { background: var(--danger); }

/* loading spinner on btn */
.btn-loading {
    position: relative;
    color: transparent !important;
}
.btn-loading::after {
    content: '';
    position: absolute;
    inset: 0;
    margin: auto;
    width: 22px;
    height: 22px;
    border: 3px solid rgba(255,255,255,0.4);
    border-top-color: #fff;
    border-radius: 50%;
    animation: spin 600ms linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
