/**
 * Housekeeping QR Report – Main Application
 * 4-screen SPA: QR Scan → Camera → Report → Success
 */

// ── State ──────────────────────────────────────────────────────────────────
const state = {
    roomId: null,
    photos: [],        // Array of { dataUrl, blob }
    voiceText: '',
    recognition: null,
    isRecording: false,
    cameraStream: null,
    qrStream: null,
    qrScanInterval: null,
    countdownTimer: null,
};

// ── Screen IDs ─────────────────────────────────────────────────────────────
const SCREENS = ['qr', 'camera', 'report', 'success'];

// ── DOM refs ───────────────────────────────────────────────────────────────
const dom = {};

document.addEventListener('DOMContentLoaded', () => {
    // Cache DOM
    dom.screens        = {};
    SCREENS.forEach(id => { dom.screens[id] = document.getElementById(`screen-${id}`); });

    dom.qrVideo        = document.getElementById('qr-video');
    dom.qrCanvas       = document.getElementById('qr-canvas');
    dom.qrInstruction  = document.getElementById('qr-instruction');
    dom.btnStartScan   = document.getElementById('btn-start-scan');

    dom.camVideo       = document.getElementById('cam-video');
    dom.camRoomNumber  = document.getElementById('cam-room-number');
    dom.photoCounter   = document.getElementById('photo-counter');
    dom.thumbnailRow   = document.getElementById('thumbnail-row');
    dom.btnShutter     = document.getElementById('btn-shutter');
    dom.btnContinue    = document.getElementById('btn-continue-photos');

    dom.rptRoomNumber  = document.getElementById('rpt-room-number');
    dom.reportImages   = document.getElementById('report-images');
    dom.btnMic         = document.getElementById('btn-mic');
    dom.micStatus      = document.getElementById('mic-status');
    dom.voiceRipple    = document.getElementById('voice-ripple');
    dom.voiceText      = document.getElementById('voice-text');
    dom.btnSubmit      = document.getElementById('btn-submit');

    dom.successRoomText = document.getElementById('success-room-text');
    dom.countdownNum    = document.getElementById('countdown-num');
    dom.btnNewRoom      = document.getElementById('btn-new-room');

    dom.toast           = document.getElementById('toast');

    // Bind events
    dom.btnStartScan.addEventListener('click', startQRScan);
    dom.btnShutter.addEventListener('click', takePhoto);
    dom.btnContinue.addEventListener('click', () => navigateTo('report'));
    dom.btnMic.addEventListener('click', toggleRecording);
    dom.voiceText.addEventListener('input', () => { state.voiceText = dom.voiceText.value; });
    dom.btnSubmit.addEventListener('click', submitReport);
    dom.btnNewRoom.addEventListener('click', resetToStart);

    // Start on QR screen
    navigateTo('qr');
    startQRScan();
});

// ── Navigation ─────────────────────────────────────────────────────────────

function navigateTo(screenId) {
    const current = SCREENS.find(id => dom.screens[id].classList.contains('active'));

    if (current) {
        dom.screens[current].classList.add('slide-out');
        setTimeout(() => dom.screens[current].classList.remove('slide-out', 'active'), 350);

        // Cleanup streams when leaving screens
        if (current === 'qr') stopQRStream();
        if (current === 'camera') stopCameraStream();
    }

    dom.screens[screenId].classList.add('active');

    // Setup new screen
    if (screenId === 'camera') setupCameraScreen();
    if (screenId === 'report') setupReportScreen();
    if (screenId === 'success') setupSuccessScreen();
}

// ── QR SCAN SCREEN ─────────────────────────────────────────────────────────

async function startQRScan() {
    dom.qrInstruction.textContent = 'Đang khởi động camera…';
    dom.btnStartScan.disabled = true;

    try {
        state.qrStream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 960 } }
        });
        dom.qrVideo.srcObject = state.qrStream;
        await dom.qrVideo.play();
        dom.qrInstruction.textContent = 'Hướng camera vào mã QR của phòng';
        dom.btnStartScan.textContent = 'Đang quét…';
        startQRDecode();
    } catch (err) {
        dom.qrInstruction.textContent = 'Không thể truy cập camera';
        dom.btnStartScan.disabled = false;
        dom.btnStartScan.textContent = 'Thử lại';
        showToast('Cần quyền truy cập camera', true);
    }
}

function startQRDecode() {
    const canvas = dom.qrCanvas;
    const ctx = canvas.getContext('2d');

    state.qrScanInterval = setInterval(() => {
        if (dom.qrVideo.readyState !== dom.qrVideo.HAVE_ENOUGH_DATA) return;

        canvas.width  = dom.qrVideo.videoWidth;
        canvas.height = dom.qrVideo.videoHeight;
        ctx.drawImage(dom.qrVideo, 0, 0, canvas.width, canvas.height);

        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const code = jsQR(imageData.data, imageData.width, imageData.height, {
            inversionAttempts: 'dontInvert',
        });

        if (code && code.data) {
            clearInterval(state.qrScanInterval);
            state.roomId = code.data.trim().toUpperCase();
            showToast(`Phòng ${state.roomId} ✓`);
            setTimeout(() => navigateTo('camera'), 600);
        }
    }, 250);
}

function stopQRStream() {
    clearInterval(state.qrScanInterval);
    if (state.qrStream) {
        state.qrStream.getTracks().forEach(t => t.stop());
        state.qrStream = null;
    }
    dom.btnStartScan.disabled = false;
    dom.btnStartScan.textContent = 'Bắt đầu quét';
}

// ── CAMERA SCREEN ──────────────────────────────────────────────────────────

async function setupCameraScreen() {
    dom.camRoomNumber.textContent = state.roomId || '---';
    renderThumbnails();
    updateCounter();

    try {
        state.cameraStream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1440 } }
        });
        dom.camVideo.srcObject = state.cameraStream;
        await dom.camVideo.play();
    } catch (err) {
        showToast('Không thể mở camera chụp ảnh', true);
    }
}

function takePhoto() {
    if (state.photos.length >= 3) return;

    const canvas = document.createElement('canvas');
    canvas.width  = dom.camVideo.videoWidth;
    canvas.height = dom.camVideo.videoHeight;
    canvas.getContext('2d').drawImage(dom.camVideo, 0, 0);

    canvas.toBlob(blob => {
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        state.photos.push({ dataUrl, blob });
        renderThumbnails();
        updateCounter();

        // Flash feedback
        dom.btnShutter.style.opacity = '0.5';
        setTimeout(() => { dom.btnShutter.style.opacity = ''; }, 150);

        if (state.photos.length === 3) {
            setTimeout(() => navigateTo('report'), 500);
        }
    }, 'image/jpeg', 0.85);
}

function deletePhoto(index) {
    state.photos.splice(index, 1);
    renderThumbnails();
    updateCounter();
}

function renderThumbnails() {
    const row = dom.thumbnailRow;
    row.innerHTML = '';

    state.photos.forEach((photo, i) => {
        const item = document.createElement('div');
        item.className = 'thumb-item';
        item.innerHTML = `
            <img src="${photo.dataUrl}" alt="Ảnh ${i + 1}">
            <button class="thumb-delete" onclick="deletePhoto(${i})" aria-label="Xóa ảnh">✕</button>
        `;
        row.appendChild(item);
    });

    // Placeholders for remaining slots
    for (let i = state.photos.length; i < 3; i++) {
        const ph = document.createElement('div');
        ph.className = 'thumb-placeholder';
        ph.innerHTML = '<span>+</span>';
        row.appendChild(ph);
    }

    // Show/hide continue button
    dom.btnContinue.style.display = (state.photos.length >= 1 && state.photos.length < 3) ? 'block' : 'none';
}

function updateCounter() {
    dom.photoCounter.textContent = `${state.photos.length} / 3`;
}

function stopCameraStream() {
    if (state.cameraStream) {
        state.cameraStream.getTracks().forEach(t => t.stop());
        state.cameraStream = null;
    }
}

// ── REPORT SCREEN ──────────────────────────────────────────────────────────

function setupReportScreen() {
    dom.rptRoomNumber.textContent = state.roomId || '---';

    // Render images
    dom.reportImages.innerHTML = state.photos.map((p, i) =>
        `<img class="report-thumb" src="${p.dataUrl}" alt="Ảnh ${i + 1}">`
    ).join('');

    // Restore voice text
    dom.voiceText.value = state.voiceText;

    // Setup speech recognition
    setupSpeechRecognition();
}

function setupSpeechRecognition() {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    state.recognition = new SpeechRecognition();
    state.recognition.lang = 'vi-VN';
    state.recognition.continuous = true;
    state.recognition.interimResults = true;

    state.recognition.onresult = (event) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
            const t = event.results[i][0].transcript;
            if (event.results[i].isFinal) final += t;
            else interim += t;
        }
        const base = state.voiceText;
        dom.voiceText.value = base + final + (interim ? `[${interim}]` : '');
        if (final) state.voiceText = base + final;
    };

    state.recognition.onerror = (e) => {
        if (e.error !== 'no-speech') {
            showToast('Không nhận diện được giọng nói', true);
        }
        stopRecording();
    };

    state.recognition.onend = () => {
        if (state.isRecording) state.recognition.start(); // keep going
    };
}

function toggleRecording() {
    if (state.isRecording) stopRecording();
    else startRecording();
}

function startRecording() {
    if (!state.recognition) {
        showToast('Trình duyệt không hỗ trợ ghi âm', true);
        return;
    }
    state.isRecording = true;
    dom.btnMic.classList.add('recording');
    dom.micStatus.textContent = '● Đang ghi âm…';
    dom.micStatus.classList.add('recording');
    dom.voiceRipple.classList.add('active');
    state.recognition.start();
}

function stopRecording() {
    state.isRecording = false;
    if (state.recognition) {
        state.recognition.onend = null; // prevent restart
        state.recognition.stop();
    }
    dom.btnMic.classList.remove('recording');
    dom.micStatus.textContent = 'Nhấn để ghi âm';
    dom.micStatus.classList.remove('recording');
    dom.voiceRipple.classList.remove('active');
}

async function submitReport() {
    if (state.photos.length < 1) {
        showToast('Cần ít nhất 1 ảnh', true);
        return;
    }
    if (!state.roomId) {
        showToast('Không có mã phòng', true);
        return;
    }

    stopRecording();

    dom.btnSubmit.classList.add('btn-loading');
    dom.btnSubmit.disabled = true;

    try {
        // Upload photos to S3
        const imageUrls = [];
        for (const photo of state.photos) {
            const filename = `housekeeping/${state.roomId}_${Date.now()}_${Math.random().toString(36).slice(2)}.jpg`;
            const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });
            await fetch(upload_url, {
                method: 'PUT',
                body: photo.blob,
                headers: { 'Content-Type': 'image/jpeg' },
            });
            imageUrls.push(file_url);
        }

        // Submit report
        await api.post('/api/reports', {
            room_id: state.roomId,
